## Тестирование CRUD операций

```python
class TestUserAPI:

    def test_create_user(self, api_client):
        user_data = {
            "name": "Test User",
            "email": f"test_{uuid.uuid4()}@example.com",
            "role": "user"
        }

        response = api_client.post("/users", json=user_data)

        assert response.status_code == 201
        assert "id" in response.json()
        assert response.json()["name"] == user_data["name"]

    def test_get_user(self, api_client):
        # Create first
        user = api_client.post("/users", json={
            "name": "Test",
            "email": "test@example.com"
        }).json()

        # Get
        response = api_client.get(f"/users/{user['id']}")

        assert response.status_code == 200
        assert response.json()["id"] == user["id"]

    def test_update_user(self, api_client):
        # Create
        user = api_client.post("/users", json={
            "name": "Original",
            "email": "test@example.com"
        }).json()

        # Update
        response = api_client.put(f"/users/{user['id']}", json={
            "name": "Updated"
        })

        assert response.status_code == 200
        assert response.json()["name"] == "Updated"

    def test_delete_user(self, api_client):
        user = api_client.post("/users", json={
            "name": "ToDelete",
            "email": "delete@example.com"
        }).json()

        response = api_client.delete(f"/users/{user['id']}")
        assert response.status_code == 204

        # Verify deletion
        response = api_client.get(f"/users/{user['id']}")
        assert response.status_code == 404
```

## Тестирование валидации

```python
def test_create_user_validation(self, api_client):
    """Test various validation scenarios"""

    # Missing required field
    response = api_client.post("/users", json={
        "name": "Test"
    })
    assert response.status_code == 400
    assert "email" in response.json()["message"]

    # Invalid email format
    response = api_client.post("/users", json={
        "name": "Test",
        "email": "invalid-email"
    })
    assert response.status_code == 400
    assert "validation" in response.json()["error"]

    # Duplicate email
    api_client.post("/users", json={
        "name": "First",
        "email": "duplicate@example.com"
    })
    response = api_client.post("/users", json={
        "name": "Second",
        "email": "duplicate@example.com"
    })
    assert response.status_code == 409
```

## Тестирование ошибок

```python
def test_404_not_found(self, api_client):
    response = api_client.get("/users/nonexistent-id")
    assert response.status_code == 404

def test_401_unauthorized(self, client_no_auth):
    response = client_no_auth.get("/users")
    assert response.status_code == 401

def test_403_forbidden(self, api_client):
    # User without admin rights trying admin action
    response = api_client.post("/admin/users", json={...})
    assert response.status_code == 403
```

## Schema validation

```python
import jsonschema

USER_SCHEMA = {
    "type": "object",
    "required": ["id", "name", "email"],
    "properties": {
        "id": {"type": "string"},
        "name": {"type": "string", "minLength": 1},
        "email": {"type": "string", "format": "email"},
        "role": {"type": "string", "enum": ["user", "admin"]}
    }
}

def test_user_schema_validation(self, api_client):
    response = api_client.get("/users/123")
    jsonschema.validate(response.json(), USER_SCHEMA)
```

## GraphQL тестирование

```python
class GraphQLClient:
    def __init__(self, url: str, headers: dict = None):
        self.url = url
        self.session = requests.Session()
        if headers:
            self.session.headers.update(headers)

    def query(self, query: str, variables: dict = None):
        response = self.session.post(
            self.url,
            json={"query": query, "variables": variables}
        )
        return response.json()

gql_client = GraphQLClient("https://api.example.com/graphql")

def test_graphql_users():
    result = gql_client.query("""
        query {
            users {
                id
                name
                email
            }
        }
    """)

    assert "errors" not in result
    assert len(result["data"]["users"]) > 0
```

## Заключение

Тестирование API требует:
- Понимания протокола HTTP и кодов ответов
- Умения работать с различными типами авторизации
- Знания схем валидации
- Инструментов для отладки (curl, Postman, httpbin)

В следующей статье разберём производительное нагрузочное тестирование.

## Что такое NixOS

NixOS — это Linux-дистрибутив с принципиально другим подходом к управлению системой. Вместо традиционных пакетов и конфигов здесь всё декларируется в одном файле.

Основные отличия:
- **Декларативная конфигурация** — вы описываете желаемое состояние, система его достигает
- **Атомарные обновления** — можно откатиться к любой предыдущей конфигурации
- **Воспроизводимое окружение** — один и тот же конфиг даёт идентичную систему
- **Изоляция пакетов** — несколько версий одного пакета могут существовать одновременно

## Установка

Скачиваем ISO с nixos.org и загружаемся. В Live-среде запускаем nixos-generate-config для создания начальной конфигурации.

```bash
# Разметка диска (пример для UEFI)
sudo parted /dev/sda -- mklabel gpt
sudo parted /dev/sda -- mkpart ESP fat32 1MiB 512MiB
sudo parted /dev/sda -- set 1 esp on
sudo parted /dev/sda -- mkpart primary linux-filesystem 512MiB 100%

# Форматирование
sudo mkfs.fat -F 32 /dev/sda1
sudo mkfs.ext4 /dev/sda2

# Монтирование
sudo mount /dev/sda2 /mnt
sudo mkdir /mnt/boot/efi
sudo mount /dev/sda1 /mnt/boot/efi

# Генерация конфигурации
sudo nixos-generate-config --root /mnt
```

## Первая конфигурация

```nix
# /etc/nixos/configuration.nix
{ config, pkgs, ... }:

{
  imports = [ ./hardware-configuration.nix ];

  boot.loader.grub.enable = true;
  boot.loader.grub.device = "/dev/sda";
  boot.loader.grub.efiSupport = true;

  networking.hostName = "nixos";
  networking.firewall.enable = false;

  time.timeZone = "Europe/Moscow";
  i18n.defaultLocale = "en_US.UTF-8";

  services.xserver.enable = true;
  services.xserver.layout = "us";
  services.xserver.displayManager.sddm.enable = true;
  services.xserver.desktopManager.plasma5.enable = true;

  users.users.alex = {
    isNormalUser = true;
    extraGroups = [ "wheel" ];
  };

  environment.systemPackages = with pkgs; [
    vim wget curl firefox
  ];

  system.stateVersion = "24.05";
}
```

## Применение конфигурации

```bash
sudo nixos-rebuild switch   # Применить без перезагрузки
sudo nixos-rebuild boot     # Применить и перезагрузиться
sudo nixos-rebuild switch --upgrade  # Обновить систему
```

## Каналы

```bash
nix-channel --list
nix-channel --add https://nixos.org/channels/nixos-unstable nixos
nix-channel --update
```

## Преимущества

- Воспроизводимое окружение на любой машине
- Несколько версий одного пакета одновременно
- Атомарные обновления с возможностью отката

Попробуйте в виртуальной машине!

## Зачем Home Manager

Home Manager управляет конфигурацией пользователя — dotfiles, переменные окружения, программы.

Преимущества:
- **Версионирование** — все dotfiles в Git
- **Воспроизводимость** — тот же конфиг на любой машине
- **Атомарность** — изменения либо применяются, либо нет

## Установка

```bash
nix-channel --add https://github.com/nix-community/home-manager/archive/master.tar.gz home-manager
nix-channel --update
nix-shell '<home-manager>' -A install
```

## Базовый home.nix

```nix
{ config, pkgs, ... }:

{
  home.username = "alex";
  home.homeDirectory = "/home/alex";

  home.packages = with pkgs; [
    git curl wget tree htop vim
  ];

  programs.git = {
    enable = true;
    userName = "Alex Galkin";
    userEmail = "alex@example.com";
  };

  programs.zsh = {
    enable = true;
    enableCompletion = true;
    shellAliases = {
      ll = "eza -la";
      g = "git";
    };
  };

  home.stateVersion = "24.05";
}
```

## Git конфиг

```nix
programs.git = {
  enable = true;
  userName = "Alex Galkin";
  userEmail = "alex@example.com";

  extraConfig = {
    pull = "rebase";
    push = "current";
    core = { editor = "vim"; };
    alias = {
      s = "status -sb";
      co = "checkout";
    };
  };
};
```

## Zsh

```nix
programs.zsh = {
  enable = true;
  enableCompletion = true;

  shellAliases = {
    ll = "eza -la";
    g = "git";
    gs = "git status";
  };
};
```

## Применение

```bash
home-manager switch        # Применить конфиг
home-manager generations   # Посмотреть поколения
home-manager rollback      # Откатиться
```

## Структура dotfiles

```
~/.dotfiles/
├── flake.nix
├── home.nix
└── modules/
    ├── git.nix
    ├── shell.nix
    └── editor.nix
```

Home Manager превращает управление dotfiles в удовольствие!
